import json
import time
from fastapi import FastAPI
import modal

app = modal.App("modal-event-pipeline")
image = modal.Image.debian_slim().pip_install("fastapi")

queue = modal.Queue.from_name("modal-event-pipeline-queue", create_if_missing=True)
volume = modal.Volume.from_name("modal-event-pipeline-vol", create_if_missing=True)
status_dict = modal.Dict.from_name("modal-event-pipeline-output", create_if_missing=True)

web_app = FastAPI()

@web_app.get("/")
def status():
    return {
        "events_produced": status_dict.get("events_produced"),
        "events_consumed": status_dict.get("events_consumed"),
        "processing_complete": status_dict.get("processing_complete"),
        "output_path": status_dict.get("output_path")
    }

@app.function(image=image)
@modal.asgi_app()
def web_endpoint():
    return web_app

@app.function(image=image)
def producer():
    events = []
    for i in range(10):
        events.append({
            "event_id": i,
            "timestamp": str(time.time()),
            "payload": f"This is a synthetic event payload number {i}"
        })
    queue.put_many(events)
    return len(events)

@app.function(image=image, volumes={"/events": volume})
def consumer():
    processed_events = []
    while True:
        try:
            # wait up to 2 seconds for a new event
            event = queue.get(timeout=2.0)
            event["processed"] = True
            event["word_count"] = len(event["payload"].split())
            processed_events.append(event)
        except Exception:
            # queue is empty
            break

    with open("/events/processed_events.json", "w") as f:
        json.dump(processed_events, f)

    volume.commit()
    return len(processed_events)

@app.local_entrypoint()
def main():
    print("Running producer...")
    produced = producer.remote()
    print(f"Produced {produced} events.")

    print("Running consumer...")
    consumed = consumer.remote()
    print(f"Consumed {consumed} events.")

    print("Updating status dictionary...")
    status_dict["events_produced"] = produced
    status_dict["events_consumed"] = consumed
    status_dict["processing_complete"] = "true"
    status_dict["output_path"] = "/events/processed_events.json"
    print("Pipeline complete.")

